async (params, browser) => {
  // Open question page
  await browser.open(`${params.question_url}`)

  // Wait for question to load
  await browser.waitForSelector('#question-header, h1, .question-hyperlink', 15000)

  // Let page render
  await browser.wait(2000)

  // Scroll to load content
  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(1500)

  // Extract question details
  const question_data = await browser.evaluate(`const titleEl = document.querySelector('#question-header h1 a, h1 a.question-hyperlink, h1'); const bodyEl = document.querySelector('#question .s-prose, #question .post-text, .question .js-post-body'); const votesEl = document.querySelector('#question .js-vote-count, .question [itemprop="upvoteCount"]'); const tagEls = document.querySelectorAll('#question .s-tag, .question .post-tag'); const tags = []; tagEls.forEach(function(t) { tags.push(t.textContent.trim()); }); const authorEl = document.querySelector('#question .user-details a, .question .post-signature:last-child .user-details a'); const dateEl = document.querySelector('#question .relativetime, .question time'); const viewsEl = document.querySelector('[title*="Viewed"], #qinfo td:nth-child(2)'); const bookmarksEl = document.querySelector('.js-bookmark-count'); const commentEls = document.querySelectorAll('#question .comment-body, .question .comment-text'); const comments = []; commentEls.forEach(function(el, idx) { if (idx < 5) { const userEl = el.querySelector('.comment-user, a'); const textEl = el.querySelector('.comment-copy, span'); comments.push({ author: userEl ? userEl.textContent.trim() : '', text: textEl ? textEl.textContent.trim().substring(0, 300) : el.textContent.trim().substring(0, 300) }); } }); const answerCountEl = document.querySelector('#answers-header h2, [data-answercount]'); return { title: titleEl ? titleEl.textContent.trim() : '', body: bodyEl ? bodyEl.textContent.trim().substring(0, 2000) : '', votes: votesEl ? votesEl.textContent.trim() : '0', tags: tags, author: authorEl ? authorEl.textContent.trim() : '', date: dateEl ? (dateEl.getAttribute('title') || dateEl.textContent.trim()) : '', views: viewsEl ? viewsEl.getAttribute('title') || viewsEl.textContent.trim() : '', bookmarks: bookmarksEl ? bookmarksEl.textContent.trim() : '0', answer_count: answerCountEl ? answerCountEl.textContent.trim() : '', comments: comments, url: window.location.href }`)

  return question_data
}
